import{_ as i,o as s,c as n,ai as r}from"./chunks/framework.ampVZV4B.js";const h=JSON.parse('{"title":"Spring Bean 生命周期与循环依赖","description":"","frontmatter":{},"headers":[],"relativePath":"framework/bean-lifecycle.md","filePath":"framework/bean-lifecycle.md"}'),a={name:"framework/bean-lifecycle.md"};function o(l,e,t,c,p,d){return s(),n("div",null,[...e[0]||(e[0]=[r(`<h1 id="spring-bean-生命周期与循环依赖" tabindex="-1">Spring Bean 生命周期与循环依赖 <a class="header-anchor" href="#spring-bean-生命周期与循环依赖" aria-label="Permalink to “Spring Bean 生命周期与循环依赖”">​</a></h1><hr><h3 id="❓-面试官-能详细说说-spring-bean-的生命周期吗-从创建到销毁经历了哪些步骤" tabindex="-1">❓ 面试官：能详细说说 Spring Bean 的生命周期吗？从创建到销毁经历了哪些步骤？ <a class="header-anchor" href="#❓-面试官-能详细说说-spring-bean-的生命周期吗-从创建到销毁经历了哪些步骤" aria-label="Permalink to “❓ 面试官：能详细说说 Spring Bean 的生命周期吗？从创建到销毁经历了哪些步骤？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> Spring Bean 的生命周期包括：<strong>实例化 → 属性填充 → 初始化 → 使用 → 销毁</strong>。其中初始化阶段会执行 <code>@PostConstruct</code>、<code>InitializingBean</code>、<code>init-method</code> 等方法。</p><p><strong>📝 详细生命周期流程（面试必背）：</strong></p><ol><li><p><strong>实例化（Instantiation）</strong>：</p><ul><li>Spring 通过反射调用构造器创建 Bean 实例。</li></ul></li><li><p><strong>属性填充（Populate Properties）</strong>：</p><ul><li>通过 <code>@Autowired</code>、<code>@Value</code> 等注解注入依赖。</li></ul></li><li><p><strong>初始化前（Before Initialization）</strong>：</p><ul><li>执行 <code>BeanPostProcessor.postProcessBeforeInitialization()</code>。</li></ul></li><li><p><strong>初始化（Initialization）</strong>：</p><ul><li>执行 <code>@PostConstruct</code> 注解的方法。</li><li>执行 <code>InitializingBean.afterPropertiesSet()</code>。</li><li>执行自定义的 <code>init-method</code>。</li></ul></li><li><p><strong>初始化后（After Initialization）</strong>：</p><ul><li>执行 <code>BeanPostProcessor.postProcessAfterInitialization()</code>（AOP 代理就是在这里创建的）。</li></ul></li><li><p><strong>使用阶段</strong>：</p><ul><li>Bean 可以被正常使用了。</li></ul></li><li><p><strong>销毁（Destroy）</strong>：</p><ul><li>容器关闭时，执行 <code>@PreDestroy</code>、<code>DisposableBean.destroy()</code>、自定义 <code>destroy-method</code>。</li></ul></li></ol><p><strong>🌟 实战应用（加分项）：</strong> &quot;在项目中，我们经常在 <code>@PostConstruct</code> 方法里做一些初始化工作，比如加载配置、预热缓存。在 <code>@PreDestroy</code> 方法里做资源清理，比如关闭线程池、释放连接。&quot;</p><hr><h3 id="❓-面试官-spring-是如何解决循环依赖的-能详细说说三级缓存机制吗-【中级】" tabindex="-1">❓ 面试官：Spring 是如何解决循环依赖的？能详细说说三级缓存机制吗？【中级】 <a class="header-anchor" href="#❓-面试官-spring-是如何解决循环依赖的-能详细说说三级缓存机制吗-【中级】" aria-label="Permalink to “❓ 面试官：Spring 是如何解决循环依赖的？能详细说说三级缓存机制吗？【中级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> Spring 通过<strong>三级缓存（三个 Map）</strong>来解决循环依赖问题。核心思想是：<strong>提前暴露半成品的 Bean（只完成了实例化，还没完成属性填充）</strong>，让其他 Bean 可以先拿到这个半成品，完成自己的初始化。</p><p><strong>📝 三级缓存详解：</strong></p><p>假设有两个类互相依赖：</p><ul><li><code>UserService</code> 依赖 <code>OrderService</code></li><li><code>OrderService</code> 依赖 <code>UserService</code></li></ul><p><strong>三级缓存结构</strong>：</p><div class="language-java line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 一级缓存：存放完整的单例 Bean（成品）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">singletonObjects</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 二级缓存：存放半成品 Bean（提前暴露的，用于解决循环依赖）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">earlySingletonObjects</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 三级缓存：存放 Bean 工厂（用于生成 AOP 代理对象）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">singletonFactories</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p><strong>解决流程（简化版）</strong>：</p><ol><li>创建 <code>UserService</code>：实例化后，放入三级缓存（工厂对象）。</li><li>填充 <code>UserService</code> 属性时，发现需要 <code>OrderService</code>。</li><li>创建 <code>OrderService</code>：实例化后，放入三级缓存。</li><li>填充 <code>OrderService</code> 属性时，发现需要 <code>UserService</code>。</li><li>从三级缓存中拿到 <code>UserService</code> 的工厂，创建半成品 <code>UserService</code>，放入二级缓存。</li><li><code>OrderService</code> 拿到半成品 <code>UserService</code>，完成自己的初始化，放入一级缓存。</li><li><code>UserService</code> 拿到完整的 <code>OrderService</code>，完成自己的初始化，放入一级缓存。</li></ol><p><strong>🌟 为什么需要三级缓存？</strong> &quot;如果只有两级缓存，当存在 AOP 代理时，无法区分是返回原始对象还是代理对象。三级缓存通过工厂模式，可以在需要时动态创建代理对象，保证循环依赖时也能正确生成 AOP 代理。&quot;</p>`,20)])])}const u=i(a,[["render",o]]);export{h as __pageData,u as default};
